/**
 * One-time: apply Aurora 1.4.0 cream contrast CSS files from media zip 12631.
 * Safe to leave inactive after run; self-guards with option kk_aurora_creamfix_140.
 */
add_action('init', function () {
	if (get_option('kk_aurora_creamfix_140') === 'done') {
		return;
	}
	if (!function_exists('get_template_directory')) {
		return;
	}

	$media_id = 12631;
	$path = get_attached_file($media_id);
	if (!$path || !file_exists($path)) {
		return;
	}

	if (!class_exists('ZipArchive')) {
		return;
	}

	$zip = new ZipArchive();
	if ($zip->open($path) !== true) {
		return;
	}

	$theme_dir = get_template_directory();
	$written = [];

	for ($i = 0; $i < $zip->numFiles; $i++) {
		$name = $zip->getNameIndex($i);
		if ($name === false || str_contains($name, '..') || str_starts_with($name, '/')) {
			continue;
		}
		$base = basename($name);
		if ($base === 'style.css') {
			$dest = $theme_dir . '/style.css';
		} elseif ($base === 'revive-port.css') {
			$dest = $theme_dir . '/assets/css/revive-port.css';
		} else {
			continue;
		}
		$contents = $zip->getFromIndex($i);
		if ($contents === false) {
			continue;
		}
		if (file_put_contents($dest, $contents) !== false) {
			$written[] = $base;
		}
	}
	$zip->close();

	if (count($written) >= 2) {
		update_option('kk_aurora_creamfix_140', 'done', false);
		update_option('kk_aurora_creamfix_140_files', $written, false);
		if (function_exists('wp_cache_flush')) {
			wp_cache_flush();
		}
	}
}, 5);
